4	export function computeThresholdState(availableQty, reservedQty, thresholdWarning, thresholdCritical) {
5	  const effective = availableQty - reservedQty;
6	  if (effective <= thresholdCritical) return 'critical';
7	  if (effective <= thresholdWarning) return 'warning';
8	  return 'normal';
9	}
