11	export async function listInventory(filters = {}) {
12	  let sql = `
13	    SELECT i.*, s.sku_code, sp.name as spu_name, w.name as warehouse_name, w.code as warehouse_code
14	    FROM inventory i
15	    JOIN skus s ON s.id = i.sku_id
16	    JOIN spus sp ON sp.id = s.spu_id
17	    JOIN warehouses w ON w.id = i.warehouse_id
18	  `;
19	  const conditions = [];
20	  const params = [];
21	  let idx = 1;
22	
23	  if (filters.warehouse_ids && Array.isArray(filters.warehouse_ids)) {
24	    if (filters.warehouse_ids.length === 0) {
25	      // Empty scope = hard deny — return nothing
26	      return [];
27	    }
28	    conditions.push(`i.warehouse_id = ANY($${idx++})`);
29	    params.push(filters.warehouse_ids);
30	  } else if (filters.warehouse_id) {
31	    conditions.push(`i.warehouse_id = $${idx++}`);
32	    params.push(filters.warehouse_id);
33	  }
34	  if (filters.sku_id) {
35	    conditions.push(`i.sku_id = $${idx++}`);
36	    params.push(filters.sku_id);
37	  }
38	
39	  if (conditions.length > 0) {
40	    sql += ' WHERE ' + conditions.join(' AND ');
41	  }
42	  sql += ' ORDER BY sp.name, s.sku_code';
43	
44	  const page = parseInt(filters.page) || 1;
45	  const limit = parseInt(filters.limit) || 20;
46	  sql += ` LIMIT $${idx++} OFFSET $${idx++}`;
47	  params.push(limit, (page - 1) * limit);
48	
49	  const result = await query(sql, params);
50	  const items = result.rows.map(row => ({
51	    ...row,
52	    threshold_state: computeThresholdState(row.available_qty, row.reserved_qty, row.threshold_warning, row.threshold_critical),
53	  }));
54	
55	  if (filters.threshold_state) {
56	    return items.filter(i => i.threshold_state === filters.threshold_state);
57	  }
58	
59	  return items;
60	}
