62	export async function createOrUpdateInventory(data) {
63	  const lotNumber = data.lot_number || null;
64	
65	  // For NULL lot_number, use advisory lock to prevent TOCTOU race
66	  if (lotNumber === null) {
67	    return transaction(async (client) => {
68	      // Advisory lock on (sku_id, warehouse_id) hash to serialize concurrent upserts
69	      const lockKey = Buffer.from(data.sku_id + data.warehouse_id).reduce((h, b) => (h * 31 + b) & 0x7fffffff, 0);
70	      await client.query('SELECT pg_advisory_xact_lock($1)', [lockKey]);
71	
72	      const existing = await client.query(
73	        'SELECT id FROM inventory WHERE sku_id = $1 AND warehouse_id = $2 AND lot_number IS NULL',
74	        [data.sku_id, data.warehouse_id]
75	      );
76	      if (existing.rows.length > 0) {
77	        const result = await client.query(
78	          `UPDATE inventory SET available_qty = $1, reserved_qty = COALESCE($2, reserved_qty),
79	           threshold_warning = COALESCE($3, threshold_warning),
80	           threshold_critical = COALESCE($4, threshold_critical), updated_at = NOW()
81	           WHERE id = $5 RETURNING *`,
82	          [data.available_qty, data.reserved_qty !== undefined ? data.reserved_qty : null,
83	           data.threshold_warning || 15, data.threshold_critical || 5, existing.rows[0].id]
84	        );
85	        return result.rows[0];
86	      }
87	
88	      // No existing row — insert within the same advisory lock
89	      const result = await client.query(
90	        `INSERT INTO inventory (sku_id, warehouse_id, lot_number, available_qty, threshold_warning, threshold_critical)
91	         VALUES ($1, $2, NULL, $3, $4, $5) RETURNING *`,
92	        [data.sku_id, data.warehouse_id, data.available_qty, data.threshold_warning || 15, data.threshold_critical || 5]
93	      );
94	      return result.rows[0];
95	    });
96	  }
97	
98	  // Non-null lot_number — normal ON CONFLICT upsert (unique constraint handles it)
99	  const hasReservedReset = data.reserved_qty !== undefined;
100	  const reservedClause = hasReservedReset ? ', reserved_qty = $7' : '';
101	  const params = [data.sku_id, data.warehouse_id, lotNumber,
102	     data.available_qty, data.threshold_warning || 15, data.threshold_critical || 5];
103	  if (hasReservedReset) params.push(parseInt(data.reserved_qty));
104	  const result = await query(
105	    `INSERT INTO inventory (sku_id, warehouse_id, lot_number, available_qty, threshold_warning, threshold_critical)
106	     VALUES ($1, $2, $3, $4, $5, $6)
107	     ON CONFLICT (sku_id, warehouse_id, lot_number)
108	     DO UPDATE SET available_qty = $4, threshold_warning = COALESCE($5, inventory.threshold_warning),
109	       threshold_critical = COALESCE($6, inventory.threshold_critical)${reservedClause}, updated_at = NOW()
110	     RETURNING *`,
111	    params
112	  );
113	  return result.rows[0];
114	}
