116	export async function updateInventory(id, data) {
117	  const result = await query(
118	    `UPDATE inventory SET available_qty = COALESCE($1, available_qty),
119	     threshold_warning = COALESCE($2, threshold_warning),
120	     threshold_critical = COALESCE($3, threshold_critical), updated_at = NOW()
121	     WHERE id = $4 RETURNING *`,
122	    [data.available_qty, data.threshold_warning, data.threshold_critical, id]
123	  );
124	  if (result.rows.length === 0) throw Errors.notFound('Inventory');
125	  return result.rows[0];
126	}
