128	export async function listWarehouses(warehouseScope = null) {
129	  if (warehouseScope && warehouseScope.length > 0) {
130	    const result = await query('SELECT * FROM warehouses WHERE id = ANY($1) ORDER BY name', [warehouseScope]);
131	    return result.rows;
132	  }
133	  const result = await query('SELECT * FROM warehouses ORDER BY name');
134	  return result.rows;
