151	export async function getInventoryForSKU(skuId, warehouseId) {
152	  const sql = warehouseId
153	    ? 'SELECT * FROM inventory WHERE sku_id = $1 AND warehouse_id = $2'
154	    : 'SELECT * FROM inventory WHERE sku_id = $1';
155	  const params = warehouseId ? [skuId, warehouseId] : [skuId];
156	  const result = await query(sql, params);
157	  return result.rows;
158	}
