1	import { authenticate, requirePermission, requireScope, getScopeFilter, resolveWarehouseScope } from '../middleware/auth.js';
2	import * as inventoryService from '../services/inventory.js';
3	import { Errors } from '../utils/errors.js';
4	
5	export default async function inventoryRoutes(fastify) {
6	  fastify.get('/api/inventory', {
7	    preHandler: [authenticate, requirePermission('inventory.read')],
8	  }, async (request) => {
9	    const warehouseScope = await resolveWarehouseScope(request.user);
10	    const filters = { ...request.query };
11	    if (warehouseScope) {
12	      filters.warehouse_ids = warehouseScope;
13	    }
14	    const items = await inventoryService.listInventory(filters);
15	    return { success: true, data: items };
16	  });
17	
18	  fastify.post('/api/inventory', {
19	    preHandler: [authenticate, requirePermission('inventory.*'), requireScope('warehouse', (req) => req.body.warehouse_id)],
20	    schema: {
21	      body: {
22	        type: 'object',
23	        required: ['sku_id', 'warehouse_id', 'available_qty'],
24	        properties: {
25	          sku_id: { type: 'string' },
26	          warehouse_id: { type: 'string' },
27	          lot_number: { type: 'string' },
28	          available_qty: { type: 'integer', minimum: 0 },
29	          threshold_warning: { type: 'integer', minimum: 0 },
30	          threshold_critical: { type: 'integer', minimum: 0 },
31	        },
32	      },
33	    },
34	  }, async (request) => {
35	    const inv = await inventoryService.createOrUpdateInventory(request.body);
36	    return { success: true, data: inv };
37	  });
38	
39	  fastify.put('/api/inventory/:id', {
40	    preHandler: [authenticate, requirePermission('inventory.*')],
41	  }, async (request) => {
42	    // Enforce warehouse scope on update
43	    const existing = await inventoryService.getInventoryById(request.params.id);
44	    const warehouseScope = getScopeFilter(request.user, 'warehouse');
45	    if (warehouseScope && existing && !warehouseScope.includes(existing.warehouse_id)) {
46	      throw Errors.scopeDenied();
47	    }
48	    const inv = await inventoryService.updateInventory(request.params.id, request.body);
49	    return { success: true, data: inv };
50	  });
51	
52	  fastify.get('/api/warehouses', {
53	    preHandler: [authenticate],
54	  }, async (request) => {
55	    const warehouseScope = await resolveWarehouseScope(request.user);
56	    if (Array.isArray(warehouseScope) && warehouseScope.length === 0) {
57	      return { success: true, data: [] };
58	    }
59	    const warehouses = await inventoryService.listWarehouses(warehouseScope);
60	    return { success: true, data: warehouses };
61	  });
62	
63	  fastify.post('/api/warehouses', {
64	    preHandler: [authenticate, requirePermission('admin.*')],
65	    schema: {
66	      body: {
67	        type: 'object',
68	        required: ['name', 'code'],
69	        properties: {
70	          name: { type: 'string' },
71	          code: { type: 'string' },
72	          address: { type: 'string' },
73	        },
74	      },
75	    },
76	  }, async (request, reply) => {
77	    const warehouse = await inventoryService.createWarehouse(request.body);
78	    reply.code(201);
79	    return { success: true, data: warehouse };
80	  });
81	}
