6	export function validateAdjacency(selectedPositions, allSlots, rowCode) {
7	  const rowSlots = allSlots
8	    .filter(s => s.row_code === rowCode)
9	    .sort((a, b) => a.position_index - b.position_index);
10	
11	  if (rowSlots.length === 0) return [];
12	
13	  const maxPos = rowSlots[rowSlots.length - 1].position_index;
14	  const minPos = rowSlots[0].position_index;
15	
16	  const selectedSet = new Set(selectedPositions);
17	  const occupiedOrSelected = new Set();
18	
19	  for (const slot of rowSlots) {
20	    if (slot.status !== 'available' || selectedSet.has(slot.position_index)) {
21	      occupiedOrSelected.add(slot.position_index);
22	    }
23	  }
24	
25	  const errors = [];
26	  for (let pos = minPos; pos <= maxPos; pos++) {
27	    if (occupiedOrSelected.has(pos)) continue;
28	
29	    const leftOccupied = pos === minPos || occupiedOrSelected.has(pos - 1);
30	    const rightOccupied = pos === maxPos || occupiedOrSelected.has(pos + 1);
31	
32	    if (leftOccupied && rightOccupied) {
33	      const isRowEnd = pos === minPos || pos === maxPos;
34	      if (!isRowEnd) {
35	        errors.push(`Selection would leave a single-seat gap at position ${pos} in row ${rowCode}`);
36	      }
37	    }
38	  }
39	
40	  return errors;
41	}
