43	export async function createHold(userId, slotIds, clientRequestKey) {
44	  return transaction(async (client) => {
45	    const existingHold = await client.query(
46	      "SELECT * FROM holds WHERE user_id = $1 AND client_request_key = $2 AND status = 'active'",
47	      [userId, clientRequestKey]
48	    );
49	    if (existingHold.rows.length > 0) {
50	      const hold = existingHold.rows[0];
51	      const holdSlots = await client.query(
52	        `SELECT cs.* FROM hold_slots hs
53	         JOIN constrained_slots cs ON cs.id = hs.slot_id
54	         WHERE hs.hold_id = $1`,
55	        [hold.id]
56	      );
57	      return { hold, slots: holdSlots.rows };
58	    }
59	
60	    const slotsResult = await client.query(
61	      `SELECT * FROM constrained_slots WHERE id = ANY($1) FOR UPDATE`,
62	      [slotIds]
63	    );
64	    if (slotsResult.rows.length !== slotIds.length) {
65	      throw Errors.notFound('One or more slots');
66	    }
67	
68	    const unavailable = slotsResult.rows.filter(s => s.status !== 'available');
69	    if (unavailable.length > 0) {
70	      throw Errors.conflict(`Slots already held/reserved: ${unavailable.map(s => `${s.row_code}-${s.position_index}`).join(', ')}`);
71	    }
72	
73	    const inventoryIds = [...new Set(slotsResult.rows.map(s => s.inventory_id))];
74	    for (const invId of inventoryIds) {
75	      const invSlots = await client.query(
76	        'SELECT * FROM constrained_slots WHERE inventory_id = $1',
77	        [invId]
78	      );
79	      const byRow = {};
80	      for (const slot of slotsResult.rows) {
81	        if (slot.inventory_id === invId) {
82	          if (!byRow[slot.row_code]) byRow[slot.row_code] = [];
83	          byRow[slot.row_code].push(slot.position_index);
84	        }
85	      }
86	      for (const [rowCode, positions] of Object.entries(byRow)) {
87	        const errors = validateAdjacency(positions, invSlots.rows, rowCode);
88	        if (errors.length > 0) {
89	          throw Errors.validation('Adjacency validation failed', { errors });
90	        }
91	      }
92	    }
93	
94	    const holdDurationResult = await client.query(
95	      "SELECT value FROM system_config WHERE key = 'hold_duration_minutes'"
96	    );
97	    const holdMinutes = holdDurationResult.rows[0]?.value?.value || 10;
98	    const expiresAt = new Date(Date.now() + holdMinutes * 60 * 1000);
99	
100	    let holdResult;
101	    try {
102	      holdResult = await client.query(
103	        `INSERT INTO holds (client_request_key, user_id, status, expires_at)
104	         VALUES ($1, $2, 'active', $3) RETURNING *`,
105	        [clientRequestKey, userId, expiresAt]
106	      );
107	    } catch (insertErr) {
108	      if (insertErr.code === '23505' && insertErr.constraint?.includes('client_request_key')) {
109	        // Race condition: another request inserted with the same key concurrently
110	        const raceHold = await client.query(
111	          "SELECT * FROM holds WHERE user_id = $1 AND client_request_key = $2",
112	          [userId, clientRequestKey]
113	        );
114	        if (raceHold.rows.length > 0) {
115	          const holdSlots = await client.query(
116	            `SELECT cs.* FROM hold_slots hs
117	             JOIN constrained_slots cs ON cs.id = hs.slot_id
118	             WHERE hs.hold_id = $1`,
119	            [raceHold.rows[0].id]
120	          );
121	          return { hold: raceHold.rows[0], slots: holdSlots.rows };
122	        }
123	      }
124	      throw insertErr;
125	    }
126	    const hold = holdResult.rows[0];
127	
128	    for (const slotId of slotIds) {
129	      await client.query(
130	        'INSERT INTO hold_slots (hold_id, slot_id) VALUES ($1, $2)',
131	        [hold.id, slotId]
132	      );
133	      await client.query(
134	        "UPDATE constrained_slots SET status = 'held' WHERE id = $1",
135	        [slotId]
136	      );
137	    }
138	
139	    await logAudit(userId, 'hold_created', 'hold', hold.id,
140	      { slots: slotIds.length, expires_at: expiresAt }, null);
141	
142	    return { hold, slots: slotsResult.rows };
143	  });
144	}
