146	export async function getHold(holdId, requestingUser = null) {
147	  const holdResult = await query('SELECT * FROM holds WHERE id = $1', [holdId]);
148	  if (holdResult.rows.length === 0) throw Errors.notFound('Hold');
149	  const hold = holdResult.rows[0];
150	
151	  if (requestingUser) {
152	    const isAdmin = requestingUser.permissions && requestingUser.permissions.some(p => p === 'admin.*');
153	    if (!isAdmin && hold.user_id !== requestingUser.id) {
154	      throw Errors.forbidden('You can only view your own holds');
155	    }
156	  }
157	
158	  const slotsResult = await query(
159	    `SELECT cs.* FROM hold_slots hs
160	     JOIN constrained_slots cs ON cs.id = hs.slot_id
161	     WHERE hs.hold_id = $1`,
162	    [holdId]
163	  );
164	
165	  return { hold, slots: slotsResult.rows };
