168	export async function cancelHold(holdId, userId) {
169	  return transaction(async (client) => {
170	    const holdResult = await client.query(
171	      "SELECT * FROM holds WHERE id = $1 AND status = 'active' FOR UPDATE",
172	      [holdId]
173	    );
174	    if (holdResult.rows.length === 0) throw Errors.notFound('Active hold');
175	    const hold = holdResult.rows[0];
176	
177	    if (hold.user_id !== userId) throw Errors.forbidden('Can only cancel your own holds');
178	
179	    await client.query("UPDATE holds SET status = 'released' WHERE id = $1", [holdId]);
180	
181	    const slots = await client.query(
182	      'SELECT slot_id FROM hold_slots WHERE hold_id = $1',
183	      [holdId]
184	    );
185	    for (const { slot_id } of slots.rows) {
186	      await client.query(
187	        "UPDATE constrained_slots SET status = 'available' WHERE id = $1",
188	        [slot_id]
189	      );
190	    }
191	
192	    await logAudit(userId, 'hold_cancelled', 'hold', holdId, {}, null);
193	    return { success: true };
194	  });
195	}
