197	export async function commitHold(holdId, userId, idempotencyKey, requestingUser = null) {
198	  return transaction(async (client) => {
199	    const existingOrder = await client.query(
200	      'SELECT id FROM orders WHERE idempotency_key = $1',
201	      [idempotencyKey]
202	    );
203	    if (existingOrder.rows.length > 0) {
204	      throw Errors.duplicate('Order already exists for this idempotency key');
205	    }
206	
207	    const holdResult = await client.query(
208	      "SELECT * FROM holds WHERE id = $1 AND status = 'active' FOR UPDATE",
209	      [holdId]
210	    );
211	    if (holdResult.rows.length === 0) throw Errors.notFound('Active hold');
212	    const hold = holdResult.rows[0];
213	
214	    if (requestingUser) {
215	      const isAdmin = requestingUser.permissions && requestingUser.permissions.some(p => p === 'admin.*');
216	      if (!isAdmin && hold.user_id !== requestingUser.id) {
217	        throw Errors.forbidden('You can only commit your own holds');
218	      }
219	    }
220	
221	    if (new Date(hold.expires_at) < new Date()) {
222	      await client.query("UPDATE holds SET status = 'expired' WHERE id = $1", [holdId]);
223	      throw Errors.conflict('Hold has expired');
224	    }
225	
226	    await client.query("UPDATE holds SET status = 'committed' WHERE id = $1", [holdId]);
227	
228	    const slots = await client.query(
229	      'SELECT slot_id FROM hold_slots WHERE hold_id = $1',
230	      [holdId]
231	    );
232	    for (const { slot_id } of slots.rows) {
233	      await client.query(
234	        "UPDATE constrained_slots SET status = 'reserved' WHERE id = $1",
235	        [slot_id]
236	      );
237	    }
238	
239	    // Calculate real order value from held slots
240	    const holdSlots = await client.query(
241	      `SELECT cs.inventory_id, i.sku_id, i.warehouse_id
242	       FROM hold_slots hs
243	       JOIN constrained_slots cs ON cs.id = hs.slot_id
244	       JOIN inventory i ON i.id = cs.inventory_id
245	       WHERE hs.hold_id = $1`,
246	      [holdId]
247	    );
248	
249	    // Group by SKU for pricing
250	    const skuGroups = {};
251	    for (const slot of holdSlots.rows) {
252	      if (!skuGroups[slot.sku_id]) {
253	        skuGroups[slot.sku_id] = { sku_id: slot.sku_id, warehouse_id: slot.warehouse_id, inventory_id: slot.inventory_id, quantity: 0 };
254	      }
255	      skuGroups[slot.sku_id].quantity++;
256	    }
257	
258	    let total = 0;
259	    const lineData = [];
260	    for (const group of Object.values(skuGroups)) {
261	      // Get preferred supplier pricing
262	      const pricingResult = await client.query(
263	        `SELECT ss.unit_price, ss.supplier_id FROM sku_suppliers ss
264	         JOIN suppliers s ON s.id = ss.supplier_id
265	         WHERE ss.sku_id = $1 AND ss.is_active = true AND s.status = 'active'
266	         ORDER BY ss.is_preferred DESC, ss.unit_price ASC LIMIT 1`,
267	        [group.sku_id]
268	      );
269	      if (pricingResult.rows.length === 0) {
270	        throw Errors.validation(`No active supplier pricing found for SKU ${group.sku_id}`);
271	      }
272	      const price = pricingResult.rows[0]?.unit_price || 0;
273	      const supplierId = pricingResult.rows[0]?.supplier_id;
274	      const lineTotal = group.quantity * parseFloat(price);
275	      total += lineTotal;
276	      lineData.push({ ...group, unit_price: price, supplier_id: supplierId, line_total: lineTotal });
277	    }
278	
279	    // Create the order with real values
280	    let orderResult;
281	    try {
282	      orderResult = await client.query(
283	        `INSERT INTO orders (buyer_user_id, idempotency_key, status, total, handling_fee, tax)
284	         VALUES ($1, $2, 'confirmed', $3, 0, 0) RETURNING *`,
285	        [userId, idempotencyKey, total]
286	      );
287	    } catch (insertErr) {
288	      if (insertErr.code === '23505' && insertErr.constraint?.includes('idempotency_key')) {
289	        throw Errors.duplicate('Order already exists for this idempotency key');
290	      }
291	      throw insertErr;
292	    }
293	
294	    // Create order lines and allocations
295	    for (const line of lineData) {
296	      const olResult = await client.query(
297	        `INSERT INTO order_lines (order_id, sku_id, supplier_id, warehouse_id, quantity, unit_price, line_total)
298	         VALUES ($1, $2, $3, $4, $5, $6, $7) RETURNING id`,
299	        [orderResult.rows[0].id, line.sku_id, line.supplier_id, line.warehouse_id, line.quantity, line.unit_price, line.line_total]
300	      );
301	      await client.query(
302	        `INSERT INTO order_line_allocations (order_line_id, inventory_id, warehouse_id, quantity)
303	         VALUES ($1, $2, $3, $4)`,
304	        [olResult.rows[0].id, line.inventory_id, line.warehouse_id, line.quantity]
305	      );
306	    }
307	
308	    // Generate fulfillment tasks
309	    const { createTasksForOrder } = await import('./tasks.js');
310	    await createTasksForOrder(orderResult.rows[0].id);
311	
312	    await logAudit(userId, 'hold_committed', 'hold', holdId, { order_id: orderResult.rows[0].id }, null);
