76	export function requirePermission(...requiredPerms) {
77	  return async (request, reply) => {
78	    if (!request.user) throw Errors.authRequired();
79	    const userPerms = request.user.permissions;
80	    const hasAdmin = userPerms.some(p => p === 'admin.*');
81	    if (hasAdmin) return;
82	
83	    for (const perm of requiredPerms) {
84	      const hasExact = userPerms.includes(perm);
85	      const hasWildcard = userPerms.some(p => {
86	        if (p.endsWith('.*')) {
87	          const prefix = p.slice(0, -1);
88	          return perm.startsWith(prefix);
89	        }
90	        return false;
91	      });
92	      if (!hasExact && !hasWildcard) {
93	        throw Errors.forbidden(`Missing permission: ${perm}`);
94	      }
95	    }
96	  };
