99	export function requireScope(scopeType, getScopeId) {
100	  return async (request, reply) => {
101	    if (!request.user) throw Errors.authRequired();
102	    const userPerms = request.user.permissions;
103	    if (userPerms.some(p => p === 'admin.*')) return;
104	
105	    const userScopes = request.user.scopes;
106	    // Users with NO scope entries at all are unrestricted (not scope-limited)
107	    if (!userScopes || userScopes.length === 0) return;
108	
109	    const relevantScopes = userScopes.filter(s => s.scope_type === scopeType);
110	    // User has scopes but none of this type — they are a scoped user
111	    // without access to this scope dimension. DEFAULT DENY.
112	    if (relevantScopes.length === 0) {
113	      throw Errors.scopeDenied();
114	    }
115	
116	    const scopeId = typeof getScopeId === 'function' ? getScopeId(request) : request.params[getScopeId];
117	    // If we can't determine the scope ID, default DENY for scoped users
118	    if (!scopeId) {
119	      throw Errors.scopeDenied();
120	    }
121	
122	    const hasScope = relevantScopes.some(s => s.scope_id === scopeId);
123	    if (!hasScope) {
124	      throw Errors.scopeDenied();
125	    }
