129	export function getScopeFilter(user, scopeType) {
130	  if (!user) return null;
131	  if (user.permissions.some(p => p === 'admin.*')) return null;
132	  // If user has ANY scopes at all, they are a scoped user
133	  if (!user.scopes || user.scopes.length === 0) return null; // truly unrestricted
134	  const scopes = user.scopes.filter(s => s.scope_type === scopeType);
135	  // User is scoped but not in this dimension — return empty array (deny all)
136	  if (scopes.length === 0) return [];
137	  return scopes.map(s => s.scope_id);
138	}
139	
140	export async function resolveWarehouseScope(user) {
141	  // Direct warehouse scope — only use if user actually HAS warehouse scopes
142	  const warehouseScope = getScopeFilter(user, 'warehouse');
143	  if (warehouseScope && warehouseScope.length > 0) return warehouseScope;
144	
145	  // Resolve store scope → warehouse IDs via mapping table
146	  const storeScope = getScopeFilter(user, 'store');
147	  if (storeScope && storeScope.length > 0) {
148	    const { query } = await import('../db/pool.js');
149	    const result = await query(
150	      'SELECT DISTINCT warehouse_id FROM store_warehouses WHERE store_id = ANY($1)',
151	      [storeScope]
152	    );
153	    if (result.rows.length > 0) {
154	      return result.rows.map(r => r.warehouse_id);
155	    }
156	    return []; // store scoped but no warehouse mapping = deny
157	  }
158	
159	  // User has scopes (warehouseScope is []) but no warehouse or store scopes → deny
160	  if (warehouseScope !== null || storeScope !== null) return [];
161	
162	  return null; // truly unrestricted
163	}
