294	export async function getRecommendations(userId, warehouseScope) {
295	  const weightsResult = await query(
296	    "SELECT value FROM system_config WHERE key = 'task_score_weights'"
297	  );
298	  const weights = weightsResult.rows[0]?.value;
299	
300	  const metricsResult = await query(
301	    'SELECT * FROM worker_metrics WHERE user_id = $1',
302	    [userId]
303	  );
304	  const workerMetric = metricsResult.rows[0] || { active_task_count: 0, reputation_score: 50 };
305	
306	  // Scope enforcement: empty array = hard deny
307	  if (Array.isArray(warehouseScope) && warehouseScope.length === 0) {
308	    return [];
309	  }
310	
311	  let tasksSql = `SELECT t.*, w.name as warehouse_name
312	    FROM tasks t LEFT JOIN warehouses w ON w.id = t.warehouse_id
313	    WHERE t.status = 'open' AND t.assigned_user_id IS NULL`;
314	  const params = [];
315	  let idx = 1;
316	  if (Array.isArray(warehouseScope) && warehouseScope.length > 0) {
317	    tasksSql += ` AND t.warehouse_id = ANY($${idx++})`;
318	    params.push(warehouseScope);
319	  } else if (warehouseScope && !Array.isArray(warehouseScope)) {
320	    // Single warehouse ID (legacy compat)
321	    tasksSql += ` AND t.warehouse_id = $${idx++}`;
322	    params.push(warehouseScope);
323	  }
324	  tasksSql += ' ORDER BY t.due_window_end ASC NULLS LAST LIMIT 20';
325	
326	  const tasksResult = await query(tasksSql, params);
327	
328	  const scored = tasksResult.rows.map(task => ({
329	    ...task,
330	    recommendation: computeTaskScore(task, workerMetric, weights),
331	  }));
332	
333	  scored.sort((a, b) => b.recommendation.total - a.recommendation.total);
334	  return scored;
