345	export async function recomputeWorkerMetrics() {
346	  const workers = await query('SELECT DISTINCT user_id FROM worker_metrics');
347	  for (const { user_id } of workers.rows) {
348	    const stats = await query(
349	      `SELECT
350	         COUNT(*) FILTER (WHERE action = 'completed') as completed,
351	         COUNT(*) FILTER (WHERE action = 'failed') as failed
352	       FROM task_history WHERE user_id = $1`,
353	      [user_id]
354	    );
355	    const completed = parseInt(stats.rows[0]?.completed || 0);
356	    const failed = parseInt(stats.rows[0]?.failed || 0);
357	    const total = completed + failed;
358	    const reputation = total > 0 ? Math.min(100, (completed / total) * 100) : 50;
359	
360	    const active = await query(
361	      "SELECT COUNT(*) FROM tasks WHERE assigned_user_id = $1 AND status IN ('accepted', 'in_progress')",
362	      [user_id]
363	    );
364	
365	    await query(
366	      `UPDATE worker_metrics SET completed_count = $1, failed_count = $2,
367	       reputation_score = $3, active_task_count = $4, last_computed_at = NOW()
368	       WHERE user_id = $5`,
369	      [completed, failed, Math.round(reputation * 100) / 100, parseInt(active.rows[0].count), user_id]
370	    );
371	  }
372	}
