374	export async function createTasksForOrder(orderId) {
375	  const order = await query('SELECT * FROM orders WHERE id = $1', [orderId]);
376	  if (order.rows.length === 0) return;
377	
378	  // Read allocation-derived warehouse assignments
379	  const allocations = await query(
380	    `SELECT ol.id as order_line_id, ol.split_group, ola.warehouse_id, ola.quantity
381	     FROM order_lines ol
382	     JOIN order_line_allocations ola ON ola.order_line_id = ol.id
383	     WHERE ol.order_id = $1
384	     ORDER BY ol.split_group, ola.warehouse_id`,
385	    [orderId]
386	  );
387	  if (allocations.rows.length === 0) return;
388	
389	  // Group by (split_group, warehouse_id) for correct task decomposition
390	  const taskGroups = {};
391	  for (const row of allocations.rows) {
392	    const key = `${row.split_group || 'default'}:${row.warehouse_id}`;
393	    if (!taskGroups[key]) {
394	      taskGroups[key] = { warehouse_id: row.warehouse_id, order_line_ids: new Set() };
395	    }
396	    taskGroups[key].order_line_ids.add(row.order_line_id);
397	  }
398	
399	  for (const group of Object.values(taskGroups)) {
400	    await query(
401	      `INSERT INTO tasks (order_id, order_line_ids, warehouse_id, status, priority, due_window_end)
402	       VALUES ($1, $2, $3, 'open', $4, $5)`,
403	      [orderId, JSON.stringify([...group.order_line_ids]), group.warehouse_id, 0,
404	       new Date(Date.now() + 24 * 60 * 60 * 1000)]
405	    );
406	  }
407	}
