5	export function computeTaskScore(task, workerMetric, weights) {
6	  const w = weights || { time_window: 0.4, workload: 0.3, reputation: 0.3 };
7	
8	  let timeWindowScore = 50;
9	  if (task.due_window_end) {
10	    const now = Date.now();
11	    const deadline = new Date(task.due_window_end).getTime();
12	    const hoursLeft = (deadline - now) / (1000 * 60 * 60);
13	    if (hoursLeft <= 0) timeWindowScore = 100;
14	    else if (hoursLeft <= 1) timeWindowScore = 90;
15	    else if (hoursLeft <= 4) timeWindowScore = 70;
16	    else if (hoursLeft <= 8) timeWindowScore = 50;
17	    else timeWindowScore = 30;
18	  }
19	
20	  let workloadScore = 50;
21	  if (workerMetric) {
22	    const active = workerMetric.active_task_count || 0;
23	    if (active === 0) workloadScore = 100;
24	    else if (active <= 2) workloadScore = 70;
25	    else if (active <= 5) workloadScore = 40;
26	    else workloadScore = 10;
27	  }
28	
29	  let reputationScore = workerMetric?.reputation_score || 50;
30	
31	  const total = (timeWindowScore * w.time_window) +
32	                (workloadScore * w.workload) +
33	                (reputationScore * w.reputation);
34	
35	  return {
36	    total: Math.round(total * 100) / 100,
37	    breakdown: { time_window: timeWindowScore, workload: workloadScore, reputation: reputationScore },
38	  };
39	}
