41	export async function listTasks(filters = {}) {
42	  let sql = `
43	    SELECT t.*, w.name as warehouse_name, u.display_name as assigned_user_name
44	    FROM tasks t
45	    LEFT JOIN warehouses w ON w.id = t.warehouse_id
46	    LEFT JOIN users u ON u.id = t.assigned_user_id
47	  `;
48	  const conditions = [];
49	  const params = [];
50	  let idx = 1;
51	
52	  if (filters.status) {
53	    conditions.push(`t.status = $${idx++}`);
54	    params.push(filters.status);
55	  }
56	  if (filters.warehouse_ids && Array.isArray(filters.warehouse_ids)) {
57	    if (filters.warehouse_ids.length === 0) {
58	      // Empty scope = hard deny — return nothing
59	      return [];
60	    }
61	    conditions.push(`t.warehouse_id = ANY($${idx++})`);
62	    params.push(filters.warehouse_ids);
63	  } else if (filters.warehouse_id) {
64	    conditions.push(`t.warehouse_id = $${idx++}`);
65	    params.push(filters.warehouse_id);
66	  }
67	  if (filters.mode === 'assigned' && filters.user_id) {
68	    conditions.push(`t.assigned_user_id = $${idx++}`);
69	    params.push(filters.user_id);
70	  }
71	  if (filters.mode === 'grab') {
72	    conditions.push(`t.assigned_user_id IS NULL`);
73	    conditions.push(`t.status = 'open'`);
74	  }
75	
76	  if (conditions.length > 0) {
77	    sql += ' WHERE ' + conditions.join(' AND ');
78	  }
79	
80	  sql += ' ORDER BY t.priority DESC, t.due_window_end ASC NULLS LAST, t.created_at ASC';
81	
82	  const page = parseInt(filters.page) || 1;
83	  const limit = parseInt(filters.limit) || 20;
84	  sql += ` LIMIT $${idx++} OFFSET $${idx++}`;
85	  params.push(limit, (page - 1) * limit);
86	
87	  const result = await query(sql, params);
88	  return result.rows;
