234	export async function updateTaskStatus(taskId, userId, newStatus) {
235	  return transaction(async (client) => {
236	    const taskResult = await client.query(
237	      'SELECT * FROM tasks WHERE id = $1 FOR UPDATE',
238	      [taskId]
239	    );
