66	export async function listSPUs(filters = {}) {
67	  let sql = `
68	    SELECT s.id, s.name, s.description, s.category_id, s.status, s.created_at, s.updated_at,
69	           c.name as category_name,
70	           (SELECT image_url FROM spu_images WHERE spu_id = s.id AND is_primary = true LIMIT 1) as primary_image,
71	           (SELECT COUNT(*) FROM skus WHERE spu_id = s.id) as sku_count,
72	           array_agg(DISTINCT t.name) FILTER (WHERE t.name IS NOT NULL) as tags
73	    FROM spus s
74	    LEFT JOIN categories c ON c.id = s.category_id
75	    LEFT JOIN spu_tags st ON st.spu_id = s.id
76	    LEFT JOIN tags t ON t.id = st.tag_id
77	  `;
78	  const conditions = [];
79	  const params = [];
80	  let idx = 1;
81	
82	  if (filters.category_id) {
83	    conditions.push(`s.category_id = $${idx++}`);
84	    params.push(filters.category_id);
85	  }
86	  if (filters.published_only) {
87	    conditions.push(`s.status = 'published'`);
88	  } else if (filters.status) {
89	    conditions.push(`s.status = $${idx++}`);
90	    params.push(filters.status);
91	  }
92	  if (filters.search) {
93	    conditions.push(`s.name ILIKE $${idx++}`);
94	    params.push(`%${filters.search}%`);
95	  }
96	  if (filters.tag) {
97	    conditions.push(`t.slug = $${idx++}`);
98	    params.push(filters.tag);
99	  }
100	
101	  if (conditions.length > 0) {
102	    sql += ' WHERE ' + conditions.join(' AND ');
103	  }
104	
105	  sql += ' GROUP BY s.id, c.name';
106	  sql += ' ORDER BY s.updated_at DESC';
107	
108	  const page = parseInt(filters.page) || 1;
109	  const limit = parseInt(filters.limit) || 20;
110	  sql += ` LIMIT $${idx++} OFFSET $${idx++}`;
111	  params.push(limit, (page - 1) * limit);
112	
113	  const result = await query(sql, params);
114	
115	  const countSql = `SELECT COUNT(DISTINCT s.id) FROM spus s
116	    LEFT JOIN spu_tags st ON st.spu_id = s.id
117	    LEFT JOIN tags t ON t.id = st.tag_id
118	    ${conditions.length > 0 ? 'WHERE ' + conditions.join(' AND ') : ''}`;
119	  const countResult = await query(countSql, params.slice(0, -2));
120	  const total = parseInt(countResult.rows[0].count);
121	
122	  return { items: result.rows, total, page, limit };
123	}
