5	export async function apiRequest(method, path, body, headers = {}) {
6	  const config = {
7	    method,
8	    headers: { ...headers },
9	  };
10	
11	  if (sessionCookie) {
12	    config.headers['Cookie'] = sessionCookie;
13	  }
14	
15	  if (body && method !== 'GET') {
16	    config.headers['Content-Type'] = 'application/json';
17	    config.body = JSON.stringify(body);
18	  }
19	
20	  const response = await fetch(`${BASE_URL}${path}`, config);
21	
22	  const setCookie = response.headers.get('set-cookie');
23	  if (setCookie && setCookie.includes('petmed_session')) {
24	    sessionCookie = setCookie.split(';')[0];
25	  }
26	
27	  const data = await response.json();
28	  return { status: response.status, data, headers: response.headers };
29	}
