3	export async function logAudit(userId, action, entityType, entityId, details, ipAddress) {
4	  const masked = maskSensitiveDetails(details);
5	  await query(
6	    `INSERT INTO audit_logs (user_id, action, entity_type, entity_id, details, ip_address)
7	     VALUES ($1, $2, $3, $4, $5, $6)`,
8	    [userId, action, entityType, entityId, JSON.stringify(masked), ipAddress]
9	  );
10	}
11	
12	const SENSITIVE_KEYS = new Set([
13	  'password', 'password_hash', 'token', 'secret_key', 'secret',
14	  'certificate_number', 'storage_path', 'storage_path_encrypted',
15	  'certificate_number_encrypted', 'encryption_key', 'session_secret',
16	]);
17	
18	function maskSensitiveDetails(details, depth = 0) {
19	  if (depth > 10) return '[DEEP]';
20	  if (!details || typeof details !== 'object') return details;
21	  if (Array.isArray(details)) {
22	    return details.map(item => maskSensitiveDetails(item, depth + 1));
23	  }
24	  const masked = {};
25	  for (const [key, value] of Object.entries(details)) {
26	    if (SENSITIVE_KEYS.has(key.toLowerCase())) {
27	      masked[key] = '[MASKED]';
28	    } else if (value && typeof value === 'object') {
29	      masked[key] = maskSensitiveDetails(value, depth + 1);
30	    } else {
31	      masked[key] = value;
32	    }
33	  }
34	  return masked;
35	}
