7	function getEncryptionKey() {
8	  const key = process.env.ENCRYPTION_KEY;
9	  if (!key && process.env.NODE_ENV === 'production') {
10	    throw new Error('ENCRYPTION_KEY environment variable must be set in production');
11	  }
12	  const keyStr = key || '0123456789abcdef0123456789abcdef';
13	  if (keyStr.length < 32) {
14	    throw new Error(`ENCRYPTION_KEY must be at least 32 characters (got ${keyStr.length})`);
15	  }
16	  return Buffer.from(keyStr, 'utf8').subarray(0, 32);
17	}
