19	export function encrypt(text) {
20	  if (!text) return null;
21	  const key = getEncryptionKey();
22	  const iv = crypto.randomBytes(IV_LENGTH);
23	  const cipher = crypto.createCipheriv(ALGORITHM, key, iv);
24	  let encrypted = cipher.update(text, 'utf8', 'hex');
25	  encrypted += cipher.final('hex');
26	  const tag = cipher.getAuthTag();
27	  return iv.toString('hex') + ':' + tag.toString('hex') + ':' + encrypted;
28	}
