30	export function decrypt(encryptedText) {
31	  if (!encryptedText) return null;
32	  const key = getEncryptionKey();
33	  const parts = encryptedText.split(':');
34	  if (parts.length !== 3) throw new Error('Invalid encrypted format');
35	  const iv = Buffer.from(parts[0], 'hex');
36	  const tag = Buffer.from(parts[1], 'hex');
37	  const encrypted = parts[2];
38	  const decipher = crypto.createDecipheriv(ALGORITHM, key, iv);
39	  decipher.setAuthTag(tag);
40	  let decrypted = decipher.update(encrypted, 'hex', 'utf8');
41	  decrypted += decipher.final('utf8');
42	  return decrypted;
