import { computeThresholdState } from '../backend/src/services/inventory.js';

describe('Constrained Inventory Reconciliation', () => {
  // These tests verify that the threshold state computation gives correct
  // results when reserved_qty is adjusted by constrained hold operations.

  test('threshold stays correct after hold creates reservation', () => {
    // Start: 100 available, 0 reserved → normal
    expect(computeThresholdState(100, 0, 15, 5)).toBe('normal');

    // After holding 90 slots: reserved_qty += 90 → effective = 100 - 90 = 10 → warning
    expect(computeThresholdState(100, 90, 15, 5)).toBe('warning');

    // After holding 96 slots: reserved_qty += 96 → effective = 100 - 96 = 4 → critical
    expect(computeThresholdState(100, 96, 15, 5)).toBe('critical');
  });

  test('threshold recovers after hold cancel releases reservation', () => {
    // Scenario: 100 available, 96 reserved (critical) → cancel 90 slots → reserved drops to 6
    // effective = 100 - 6 = 94 → normal
    expect(computeThresholdState(100, 96, 15, 5)).toBe('critical');
    expect(computeThresholdState(100, 6, 15, 5)).toBe('normal');
  });

  test('threshold recovers after hold expiry releases reservation', () => {
    // Same as cancel — expired holds release the same reserved_qty
    expect(computeThresholdState(50, 46, 15, 5)).toBe('critical');
