import { loginAsAdmin, loginAsBuyer, loginAsDispatcher, clearSession, apiRequest } from './helpers.js';

/**
 * Section 4: Inventory write-scope consistency tests.
 *
 * Verifies that inventory create/update honors resolved warehouse scope
 * (direct warehouse + store→warehouse mapping), not just direct warehouse scope.
