 * Seed data assumptions:
 * - buyer1 is scoped to store ST-DT01 which maps to warehouse WH-MAIN (c0000000-...01)
 * - admin has admin.* (unrestricted)
 * - dispatcher1 has task.* but NOT inventory.* permission
 */

const WH_MAIN = 'c0000000-0000-0000-0000-000000000001';
const SKU_A = '14000000-0000-0000-0000-000000000001';

describe('Inventory Write Scope Consistency', () => {
  test('admin can write inventory to any warehouse', async () => {
    clearSession();
    await loginAsAdmin();
    const res = await apiRequest('POST', '/api/inventory', {
      sku_id: SKU_A,
      warehouse_id: WH_MAIN,
      available_qty: 9999,
    });
    expect(res.status).toBe(200);
  });

  test('dispatcher without inventory.* cannot write inventory', async () => {
    clearSession();
    await loginAsDispatcher();
    const res = await apiRequest('POST', '/api/inventory', {
      sku_id: SKU_A,
      warehouse_id: WH_MAIN,
      available_qty: 100,
    });
    expect(res.status).toBe(403);
  });

  test('buyer (store-scoped, no inventory perm) cannot write inventory', async () => {
    clearSession();
    await loginAsBuyer();
    const res = await apiRequest('POST', '/api/inventory', {
      sku_id: SKU_A,
      warehouse_id: WH_MAIN,
      available_qty: 100,
    });
    expect(res.status).toBe(403);
  });

  test('admin can update inventory via PUT', async () => {
    clearSession();
    await loginAsAdmin();
    // Get an inventory record
    const listRes = await apiRequest('GET', '/api/inventory?limit=1');
    expect(listRes.status).toBe(200);
    if (listRes.data.data?.length > 0) {
      const invId = listRes.data.data[0].id;
      const res = await apiRequest('PUT', `/api/inventory/${invId}`, {
        available_qty: 8888,
      });
      expect(res.status).toBe(200);
    }
  });
});
"}

