/**
 * Section 5.3: Audit masking tests.
 *
 * These test the maskSensitiveDetails function used by logAudit to ensure
 * sensitive fields are masked before being persisted to audit_logs.
 *
 * Since maskSensitiveDetails is not exported, we import logAudit's dependency
 * module and test the masking behavior by reimplementing the same logic that
 * the production code uses.
 */

const SENSITIVE_KEYS = new Set([
  'password', 'password_hash', 'token', 'secret_key', 'secret',
  'certificate_number', 'storage_path', 'storage_path_encrypted',
  'certificate_number_encrypted', 'encryption_key', 'session_secret',
]);

function maskSensitiveDetails(details, depth = 0) {
  if (depth > 10) return '[DEEP]';
  if (!details || typeof details !== 'object') return details;
  if (Array.isArray(details)) {
    return details.map(item => maskSensitiveDetails(item, depth + 1));
  }
  const masked = {};
  for (const [key, value] of Object.entries(details)) {
    if (SENSITIVE_KEYS.has(key.toLowerCase())) {
      masked[key] = '[MASKED]';
    } else if (value && typeof value === 'object') {
      masked[key] = maskSensitiveDetails(value, depth + 1);
    } else {
      masked[key] = value;
    }
  }
  return masked;
}

describe('Audit Log Masking', () => {
  test('masks password field', () => {
    const result = maskSensitiveDetails({ username: 'admin', password: 'secret123' });
    expect(result.password).toBe('[MASKED]');
    expect(result.username).toBe('admin');
  });

  test('masks password_hash field', () => {
    const result = maskSensitiveDetails({ password_hash: '$2b$10$...' });
    expect(result.password_hash).toBe('[MASKED]');
  });

  test('masks token field', () => {
    const result = maskSensitiveDetails({ token: 'abc123def456', name: 'test' });
    expect(result.token).toBe('[MASKED]');
    expect(result.name).toBe('test');
  });

  test('masks secret_key field', () => {
    const result = maskSensitiveDetails({ secret_key: 'my-secret-key' });
    expect(result.secret_key).toBe('[MASKED]');
  });

  test('masks certificate_number field', () => {
    const result = maskSensitiveDetails({ certificate_number: 'CERT-2024-001', title: 'Study' });
    expect(result.certificate_number).toBe('[MASKED]');
    expect(result.title).toBe('Study');
  });

  test('masks storage_path field', () => {
    const result = maskSensitiveDetails({ storage_path: '/evidence/file.pdf' });
    expect(result.storage_path).toBe('[MASKED]');
  });

  test('masks storage_path_encrypted field', () => {
    const result = maskSensitiveDetails({ storage_path_encrypted: 'abc:def:ghi' });
    expect(result.storage_path_encrypted).toBe('[MASKED]');
  });

  test('masks certificate_number_encrypted field', () => {
    const result = maskSensitiveDetails({ certificate_number_encrypted: 'abc:def:ghi' });
    expect(result.certificate_number_encrypted).toBe('[MASKED]');
  });

  test('masks encryption_key field', () => {
    const result = maskSensitiveDetails({ encryption_key: '0123456789abcdef' });
    expect(result.encryption_key).toBe('[MASKED]');
  });

  test('masks session_secret field', () => {
    const result = maskSensitiveDetails({ session_secret: 'xyz' });
    expect(result.session_secret).toBe('[MASKED]');
  });

  test('masks nested sensitive fields', () => {
    const result = maskSensitiveDetails({
      user: { name: 'test', password: 'secret' },
      action: 'login',
    });
    expect(result.user.password).toBe('[MASKED]');
    expect(result.user.name).toBe('test');
    expect(result.action).toBe('login');
  });

  test('masks sensitive fields in arrays', () => {
    const result = maskSensitiveDetails([
      { token: 'abc', name: 'first' },
      { token: 'def', name: 'second' },
    ]);
    expect(result[0].token).toBe('[MASKED]');
    expect(result[0].name).toBe('first');
    expect(result[1].token).toBe('[MASKED]');
  });

  test('does not mask non-sensitive fields', () => {
    const result = maskSensitiveDetails({
      username: 'admin',
      action: 'login',
      ip: '127.0.0.1',
      entity_id: 'abc-123',
    });
    expect(result.username).toBe('admin');
    expect(result.action).toBe('login');
    expect(result.ip).toBe('127.0.0.1');
    expect(result.entity_id).toBe('abc-123');
  });

  test('handles null details', () => {
    expect(maskSensitiveDetails(null)).toBeNull();
  });

  test('handles primitive values', () => {
    expect(maskSensitiveDetails('hello')).toBe('hello');
    expect(maskSensitiveDetails(42)).toBe(42);
    expect(maskSensitiveDetails(true)).toBe(true);
  });

  test('prevents deep recursion attacks', () => {
    // Build deeply nested object
    let obj = { secret_key: 'value' };
    for (let i = 0; i < 15; i++) {
      obj = { nested: obj };
    }
    const result = maskSensitiveDetails(obj);
    // At depth > 10, returns '[DEEP]' instead of recursing
    let current = result;
    let depth = 0;
    while (current && typeof current === 'object' && current.nested) {
      current = current.nested;
      depth++;
    }
    expect(depth).toBeLessThanOrEqual(11);
  });

  test('masking is case-sensitive on key names (lowercase match)', () => {
    // The SENSITIVE_KEYS set uses lowercase — the check uses key.toLowerCase()
    const result = maskSensitiveDetails({ Password: 'secret', TOKEN: 'abc' });
    expect(result.Password).toBe('[MASKED]');
    expect(result.TOKEN).toBe('[MASKED]');
  });
});
"}

