/**
 * Section 5.1: Session inactivity timeout unit tests.
 *
 * The auth middleware enforces an 8-hour inactivity timeout by comparing
 * last_activity_at + 8 hours against current time. These tests verify the
 * timeout logic without requiring a database.
 */

const SESSION_TIMEOUT_HOURS = 8;

function isSessionExpiredByInactivity(lastActivityAt) {
  const lastActivity = new Date(lastActivityAt);
  const inactivityLimit = new Date(lastActivity.getTime() + SESSION_TIMEOUT_HOURS * 60 * 60 * 1000);
  return new Date() > inactivityLimit;
}

describe('Session Inactivity Timeout', () => {
  test('session active 1 minute ago is NOT expired', () => {
    const lastActivity = new Date(Date.now() - 1 * 60 * 1000); // 1 min ago
    expect(isSessionExpiredByInactivity(lastActivity)).toBe(false);
  });

  test('session active 7 hours ago is NOT expired', () => {
    const lastActivity = new Date(Date.now() - 7 * 60 * 60 * 1000); // 7 hours ago
    expect(isSessionExpiredByInactivity(lastActivity)).toBe(false);
  });

  test('session active 7h59m ago is NOT expired', () => {
    const lastActivity = new Date(Date.now() - (7 * 60 + 59) * 60 * 1000); // 7h59m ago
    expect(isSessionExpiredByInactivity(lastActivity)).toBe(false);
  });

  test('session active exactly 8 hours ago is expired (boundary)', () => {
    // At exactly 8 hours, inactivityLimit === now, so > fails, NOT expired
    // But 8 hours + 1ms IS expired
    const lastActivity = new Date(Date.now() - 8 * 60 * 60 * 1000 - 1); // 8h + 1ms ago
    expect(isSessionExpiredByInactivity(lastActivity)).toBe(true);
  });

  test('session active 9 hours ago is expired', () => {
    const lastActivity = new Date(Date.now() - 9 * 60 * 60 * 1000);
    expect(isSessionExpiredByInactivity(lastActivity)).toBe(true);
  });

  test('session active 24 hours ago is expired', () => {
    const lastActivity = new Date(Date.now() - 24 * 60 * 60 * 1000);
    expect(isSessionExpiredByInactivity(lastActivity)).toBe(true);
  });

  test('session active just now is NOT expired', () => {
    const lastActivity = new Date();
    expect(isSessionExpiredByInactivity(lastActivity)).toBe(false);
  });

  test('timeout constant is 8 hours', () => {
    expect(SESSION_TIMEOUT_HOURS).toBe(8);
  });
});
"}

