import { computeFileChecksum } from '../backend/src/utils/crypto.js';

/**
 * Section 5.4: Evidence integrity / tamper detection tests.
 *
 * The evidence system stores a SHA-256 checksum at upload time and verifies
 * it at download time. If the file has been tampered with, the checksum won't
 * match and the download should fail.
 *
 * These tests verify the checksum computation and tamper detection logic
 * without requiring filesystem or database access.
 */

describe('Evidence Integrity', () => {
  test('checksum is consistent for same content', () => {
    const content = Buffer.from('test evidence file content');
    const checksum1 = computeFileChecksum(content);
    const checksum2 = computeFileChecksum(content);
    expect(checksum1).toBe(checksum2);
  });

  test('checksum differs for different content', () => {
    const original = Buffer.from('original evidence file');
    const tampered = Buffer.from('tampered evidence file');
    const checksumOriginal = computeFileChecksum(original);
    const checksumTampered = computeFileChecksum(tampered);
    expect(checksumOriginal).not.toBe(checksumTampered);
  });

  test('checksum is a 64-char hex string (SHA-256)', () => {
    const content = Buffer.from('test');
    const checksum = computeFileChecksum(content);
    expect(checksum).toMatch(/^[a-f0-9]{64}$/);
  });

  test('tamper detection: modified file fails checksum comparison', () => {
    // Simulate upload
    const originalContent = Buffer.from('important evidence document');
    const storedChecksum = computeFileChecksum(originalContent);

    // Simulate tampering
    const tamperedContent = Buffer.from('important evidence document - MODIFIED');
    const currentChecksum = computeFileChecksum(tamperedContent);

    // Tamper detection
    const integrityOk = currentChecksum === storedChecksum;
    expect(integrityOk).toBe(false);
  });

  test('integrity check passes for untampered file', () => {
    const content = Buffer.from('important evidence document');
    const storedChecksum = computeFileChecksum(content);

    // Download same content
    const downloadedChecksum = computeFileChecksum(content);
    expect(downloadedChecksum).toBe(storedChecksum);
  });

  test('empty file has valid checksum', () => {
    const empty = Buffer.from('');
