  test('checksum is consistent for same content', () => {
    const content = Buffer.from('test evidence file content');
    const checksum1 = computeFileChecksum(content);
    const checksum2 = computeFileChecksum(content);
    expect(checksum1).toBe(checksum2);
  });

  test('checksum differs for different content', () => {
    const original = Buffer.from('original evidence file');
    const tampered = Buffer.from('tampered evidence file');
    const checksumOriginal = computeFileChecksum(original);
    const checksumTampered = computeFileChecksum(tampered);
    expect(checksumOriginal).not.toBe(checksumTampered);
  });

  test('checksum is a 64-char hex string (SHA-256)', () => {
    const content = Buffer.from('test');
    const checksum = computeFileChecksum(content);
    expect(checksum).toMatch(/^[a-f0-9]{64}$/);
  });

