    // Simulate upload
    const originalContent = Buffer.from('important evidence document');
    const storedChecksum = computeFileChecksum(originalContent);

    // Simulate tampering
    const tamperedContent = Buffer.from('important evidence document - MODIFIED');
    const currentChecksum = computeFileChecksum(tamperedContent);

