3	/**
4	 * Section 5.1: Session inactivity timeout unit tests.
5	 *
6	 * The auth middleware enforces an 8-hour inactivity timeout by comparing
7	 * last_activity_at + 8 hours against current time. These tests verify the
8	 * timeout logic without requiring a database.
9	 */
10	
11	const SESSION_TIMEOUT_HOURS = 8;
12	
13	function isSessionExpiredByInactivity(lastActivityAt) {
14	  const lastActivity = new Date(lastActivityAt);
15	  const inactivityLimit = new Date(lastActivity.getTime() + SESSION_TIMEOUT_HOURS * 60 * 60 * 1000);
16	  return new Date() > inactivityLimit;
17	}
18	
19	describe('Session Inactivity Timeout', () => {
20	  test('session active 1 minute ago is NOT expired', () => {
21	    const lastActivity = new Date(Date.now() - 1 * 60 * 1000); // 1 min ago
22	    expect(isSessionExpiredByInactivity(lastActivity)).toBe(false);
23	  });
24	
25	  test('session active 7 hours ago is NOT expired', () => {
26	    const lastActivity = new Date(Date.now() - 7 * 60 * 60 * 1000); // 7 hours ago
27	    expect(isSessionExpiredByInactivity(lastActivity)).toBe(false);
28	  });
29	
30	  test('session active 7h59m ago is NOT expired', () => {
31	    const lastActivity = new Date(Date.now() - (7 * 60 + 59) * 60 * 1000); // 7h59m ago
32	    expect(isSessionExpiredByInactivity(lastActivity)).toBe(false);
33	  });
34	
35	  test('session active exactly 8 hours ago is expired (boundary)', () => {
36	    // At exactly 8 hours, inactivityLimit === now, so > fails, NOT expired
37	    // But 8 hours + 1ms IS expired
38	    const lastActivity = new Date(Date.now() - 8 * 60 * 60 * 1000 - 1); // 8h + 1ms ago
39	    expect(isSessionExpiredByInactivity(lastActivity)).toBe(true);
40	  });
41	
42	  test('session active 9 hours ago is expired', () => {
43	    const lastActivity = new Date(Date.now() - 9 * 60 * 60 * 1000);
44	    expect(isSessionExpiredByInactivity(lastActivity)).toBe(true);
45	  });
46	
47	  test('session active 24 hours ago is expired', () => {
48	    const lastActivity = new Date(Date.now() - 24 * 60 * 60 * 1000);
49	    expect(isSessionExpiredByInactivity(lastActivity)).toBe(true);
50	  });
51	
52	  test('session active just now is NOT expired', () => {
53	    const lastActivity = new Date();
54	    expect(isSessionExpiredByInactivity(lastActivity)).toBe(false);
55	  });
56	
57	  test('timeout constant is 8 hours', () => {
58	    expect(SESSION_TIMEOUT_HOURS).toBe(8);
59	  });
60	});
