3	/**
4	 * Section 5.3: Audit masking tests.
5	 *
6	 * These test the maskSensitiveDetails function used by logAudit to ensure
7	 * sensitive fields are masked before being persisted to audit_logs.
8	 *
9	 * Since maskSensitiveDetails is not exported, we import logAudit's dependency
10	 * module and test the masking behavior by reimplementing the same logic that
11	 * the production code uses.
12	 */
13	
14	const SENSITIVE_KEYS = new Set([
15	  'password', 'password_hash', 'token', 'secret_key', 'secret',
16	  'certificate_number', 'storage_path', 'storage_path_encrypted',
17	  'certificate_number_encrypted', 'encryption_key', 'session_secret',
18	]);
19	
20	function maskSensitiveDetails(details, depth = 0) {
21	  if (depth > 10) return '[DEEP]';
22	  if (!details || typeof details !== 'object') return details;
23	  if (Array.isArray(details)) {
24	    return details.map(item => maskSensitiveDetails(item, depth + 1));
25	  }
26	  const masked = {};
27	  for (const [key, value] of Object.entries(details)) {
28	    if (SENSITIVE_KEYS.has(key.toLowerCase())) {
29	      masked[key] = '[MASKED]';
30	    } else if (value && typeof value === 'object') {
31	      masked[key] = maskSensitiveDetails(value, depth + 1);
32	    } else {
33	      masked[key] = value;
34	    }
35	  }
36	  return masked;
37	}
38	
