3	async function request(method, path, body, options = {}) {
4	  const config = {
5	    method,
6	    headers: { 'Content-Type': 'application/json' },
7	    credentials: 'include',
8	    ...options,
9	  };
10	
11	  if (body && method !== 'GET') {
12	    if (body instanceof FormData) {
13	      delete config.headers['Content-Type'];
14	      config.body = body;
15	    } else {
16	      config.body = JSON.stringify(body);
17	    }
18	  }
19	
20	  const response = await fetch(`${BASE_URL}${path}`, config);
21	
22	  // Handle empty responses (204 No Content, etc.)
23	  if (response.status === 204 || response.headers.get('Content-Length') === '0') {
24	    if (!response.ok) {
25	      const error = new Error(response.statusText || 'Request failed');
26	      error.status = response.status;
27	      throw error;
28	    }
29	    return { success: true, data: null };
30	  }
31	
32	  const contentType = response.headers.get('Content-Type') || '';
33	  if (!contentType.includes('application/json')) {
34	    if (!response.ok) {
35	      const error = new Error(response.statusText || 'Request failed');
36	      error.status = response.status;
37	      throw error;
38	    }
39	    return { success: false, error: { message: response.statusText } };
40	  }
41	
42	  const data = await response.json();
43	
44	  if (!response.ok) {
45	    const error = new Error(data.error?.message || 'Request failed');
46	    error.code = data.error?.code;
47	    error.status = response.status;
48	    error.details = data.error?.details;
49	    throw error;
50	  }
51	
52	  return data;
53	}
