31	export function validateAdjacency(selectedPositions, allSlots, rowCode) {
32	  const rowSlots = allSlots
33	    .filter(s => s.row_code === rowCode)
34	    .sort((a, b) => a.position_index - b.position_index);
35	
36	  if (rowSlots.length === 0) return [];
37	
38	  const maxPos = rowSlots[rowSlots.length - 1].position_index;
39	  const minPos = rowSlots[0].position_index;
40	
41	  const selectedSet = new Set(selectedPositions);
42	  const occupiedOrSelected = new Set();
43	
44	  for (const slot of rowSlots) {
45	    if (slot.status !== 'available' || selectedSet.has(slot.position_index)) {
46	      occupiedOrSelected.add(slot.position_index);
47	    }
48	  }
49	
50	  const errors = [];
51	  for (let pos = minPos; pos <= maxPos; pos++) {
52	    if (occupiedOrSelected.has(pos)) continue;
53	
54	    const leftOccupied = pos === minPos || occupiedOrSelected.has(pos - 1);
55	    const rightOccupied = pos === maxPos || occupiedOrSelected.has(pos + 1);
56	
57	    if (leftOccupied && rightOccupied) {
58	      const isRowEnd = pos === minPos || pos === maxPos;
59	      if (!isRowEnd) {
60	        errors.push(`Selection would leave a single-seat gap at position ${pos} in row ${rowCode}`);
61	      }
62	    }
63	  }
64	
65	  return errors;
66	}
