164	    // Sync aggregate inventory: holding slots increases reserved count
165	    await adjustInventoryReserved(client, slotIds, +1);
166	
167	    await logAudit(userId, 'hold_created', 'hold', hold.id,
168	      { slots: slotIds.length, expires_at: expiresAt }, null);
