{"file_path": "/Users/aimanmengesha/Desktop/eagle point/Slopering/w2t11/repo/unit_tests/evidence_integrity.test.js", "content": "import { describe, test, expect, afterAll } from '@jest/globals';
import { computeFileChecksum } from '../backend/src/utils/crypto.js';
import { uploadEvidence, downloadEvidence } from '../backend/src/services/outcomes.js';
import { query } from '../backend/src/db/pool.js';
import fs from 'fs/promises';
import path from 'path';

/**
 * Evidence integrity — production-path tests.
 *
 * Tests the REAL uploadEvidence / downloadEvidence service functions,
 * including checksum storage, filesystem write, and tamper detection.
 * Requires a running PostgreSQL instance.
 */

const EVIDENCE_PATH = process.env.EVIDENCE_STORAGE_PATH || './evidence-storage';

// Helper: find or create a usable outcome + user for evidence tests
async function getTestFixtures() {
  // Use reviewer1 user (has evidence.* via outcomes_reviewer role)
  const userRes = await query("SELECT id FROM users WHERE username = 'reviewer1'");
  if (userRes.rows.length === 0) throw new Error('reviewer1 user not found — run seed first');
  const userId = userRes.rows[0].id;

  // Find an existing outcome, or create one
  let outcomeRes = await query('SELECT id FROM outcomes LIMIT 1');
  if (outcomeRes.rows.length === 0) {
    outcomeRes = await query(
      `INSERT INTO outcomes (type, title, status, created_by)
       VALUES ('study', 'Evidence Test Outcome', 'draft', $1) RETURNING id`,
      [userId],
    );
  }
  return { userId, outcomeId: outcomeRes.rows[0].id };
}

// Track evidence files created during tests for cleanup
const createdEvidenceIds = [];

afterAll(async () => {
  // Clean up evidence rows + files we created
  for (const id of createdEvidenceIds) {
    try {
      const ev = await query('SELECT storage_path_encrypted FROM evidence WHERE id = $1', [id]);
      if (ev.rows.length > 0) {
        // We can't easily decrypt here, but the row cleanup is enough
        await query('DELETE FROM evidence WHERE id = $1', [id]);
      }
    } catch { /* ignore cleanup errors */ }
  }
});

describe('Evidence Integrity — production path', () => {
  test('uploadEvidence stores correct checksum and file', async () => {
    const { userId, outcomeId } = await getTestFixtures();
    const content = Buffer.from('evidence-upload-test-' + Date.now());
    const expectedChecksum = computeFileChecksum(content);

    const result = await uploadEvidence(outcomeId, {
      buffer: content,
      filename: 'test-upload.txt',
      mimetype: 'text/plain',
    }, userId);

    createdEvidenceIds.push(result.id);
    expect(result.checksum_sha256).toBe(expectedChecksum);
    expect(result.file_name).toBe('test-upload.txt');
    expect(result.file_size).toBe(content.length);
  });

  test('downloadEvidence succeeds for untampered file', async () => {
    const { userId, outcomeId } = await getTestFixtures();
    const content = Buffer.from('untampered-evidence-' + Date.now());

    const uploaded = await uploadEvidence(outcomeId, {
      buffer: content,
      filename: 'untampered.txt',
      mimetype: 'text/plain',
    }, userId);
    createdEvidenceIds.push(uploaded.id);

    const downloaded = await downloadEvidence(uploaded.id, userId);
    expect(downloaded.filename).toBe('untampered.txt');
    expect(downloaded.buffer.equals(content)).toBe(true);
  });

  test('downloadEvidence rejects tampered file', async () => {
    const { userId, outcomeId } = await getTestFixtures();
    const content = Buffer.from('tamper-test-evidence-' + Date.now());

    const uploaded = await uploadEvidence(outcomeId, {
      buffer: content,
      filename: 'tamper-target.txt',
      mimetype: 'text/plain',
    }, userId);
    createdEvidenceIds.push(uploaded.id);

    // Resolve the actual file path from the DB (decrypt in service)
    const { decrypt } = await import('../backend/src/utils/crypto.js');
    const evRow = await query('SELECT storage_path_encrypted FROM evidence WHERE id = $1', [uploaded.id]);
    const storagePath = decrypt(evRow.rows[0].storage_path_encrypted);

    // Tamper with the file on disk
    await fs.writeFile(storagePath, 'THIS FILE HAS BEEN TAMPERED WITH');

    // Download should fail with integrity error
    await expect(downloadEvidence(uploaded.id, userId))
      .rejects.toThrow(/integrity/i);
  });
});
"}

