{"file_path": "/Users/aimanmengesha/Desktop/eagle point/Slopering/w2t11/repo/API_tests/inventory_scope.test.js", "content": "import { describe, test, expect, beforeAll, afterAll } from '@jest/globals';
import { loginAsAdmin, loginAsBuyer, loginAsDispatcher, clearSession, apiRequest, login } from './helpers.js';
import { dbQuery, closeDb } from './testDb.js';

/**
 * Inventory write-scope consistency tests (production path).
 *
 * Proves the original bug fix: inventory writes now honour resolved
 * store→warehouse scope, not just direct warehouse scope.
 *
 * Test fixture: a user ("invwriter") with inventory.* permission and
 * a store scope that maps to WH-MAIN.
 */

const WH_MAIN = 'c0000000-0000-0000-0000-000000000001';
const WH_EAST = 'c0000000-0000-0000-0000-000000000002';
const SKU_A = '14000000-0000-0000-0000-000000000001';
const STORE_DT01 = 'd0000000-0000-0000-0000-000000000001'; // maps to WH-MAIN only

describe('Inventory Write Scope Consistency', () => {
  const testUsername = `invwriter_${Date.now()}`;

  beforeAll(async () => {
    // Create a test role with inventory.* (no admin.*)
    const roleId = 'aaaa0000-test-role-0000-000000000001';
    await dbQuery(
      `INSERT INTO roles (id, name, description, permissions)
       VALUES ($1, $2, $3, $4)
       ON CONFLICT (name) DO UPDATE SET permissions = $4`,
      [roleId, 'inventory_writer_test', 'Test role for inventory write', '["inventory.*", "catalog.read"]'],
    );

    // Create a test user with that role and a STORE scope (not warehouse)
    clearSession();
    await loginAsAdmin();
    await apiRequest('POST', '/api/users', {
      username: testUsername,
      password: 'password123',
      display_name: 'Inv Write Tester',
      roles: ['inventory_writer_test'],
      scopes: [{ type: 'store', id: STORE_DT01 }],
    });
    clearSession();
  });

  afterAll(async () => {
    // Cleanup
    await dbQuery("DELETE FROM user_scopes WHERE user_id = (SELECT id FROM users WHERE username = $1)", [testUsername]);
    await dbQuery("DELETE FROM user_roles WHERE user_id = (SELECT id FROM users WHERE username = $1)", [testUsername]);
    await dbQuery('DELETE FROM sessions WHERE user_id = (SELECT id FROM users WHERE username = $1)', [testUsername]);
    await dbQuery('DELETE FROM users WHERE username = $1', [testUsername]);
    await dbQuery("DELETE FROM roles WHERE name = 'inventory_writer_test'");
    await closeDb();
  });

  test('store-scoped user can write inventory to mapped warehouse', async () => {
    clearSession();
    const loginRes = await login(testUsername, 'password123');
    expect(loginRes.status).toBe(200);

    // ST-DT01 maps to WH-MAIN, so this should be allowed
    const res = await apiRequest('POST', '/api/inventory', {
      sku_id: SKU_A,
      warehouse_id: WH_MAIN,
      available_qty: 7777,
    });
    expect(res.status).toBe(200);
  });

  test('store-scoped user is denied write to unmapped warehouse', async () => {
    clearSession();
    await login(testUsername, 'password123');

    // ST-DT01 does NOT map to WH-EAST, so this must be denied
    const res = await apiRequest('POST', '/api/inventory', {
      sku_id: SKU_A,
      warehouse_id: WH_EAST,
      available_qty: 100,
    });
    expect(res.status).toBe(403);
  });

  test('admin can write inventory to any warehouse', async () => {
    clearSession();
    await loginAsAdmin();
    const res = await apiRequest('POST', '/api/inventory', {
      sku_id: SKU_A,
      warehouse_id: WH_MAIN,
      available_qty: 9999,
    });
    expect(res.status).toBe(200);
  });

  test('dispatcher without inventory.* cannot write inventory', async () => {
    clearSession();
    await loginAsDispatcher();
    const res = await apiRequest('POST', '/api/inventory', {
      sku_id: SKU_A,
      warehouse_id: WH_MAIN,
      available_qty: 100,
    });
    expect(res.status).toBe(403);
  });
});
"}

