{"file_path": "/Users/aimanmengesha/Desktop/eagle point/Slopering/w2t11/repo/API_tests/evidence_integrity.test.js", "content": "import { describe, test, expect, afterAll } from '@jest/globals';
import { loginAsReviewer, loginAsAdmin, clearSession, apiRequest } from './helpers.js';
import { dbQuery, closeDb } from './testDb.js';
import { computeFileChecksum } from '../backend/src/utils/crypto.js';
import { uploadEvidence, downloadEvidence } from '../backend/src/services/outcomes.js';
import { decrypt } from '../backend/src/utils/crypto.js';
import fs from 'fs/promises';

/**
 * Evidence integrity — full production upload/download/tamper path.
 * Requires a running backend + database.
 */

const createdEvidenceIds = [];

async function getTestFixtures() {
  const userRes = await dbQuery("SELECT id FROM users WHERE username = 'reviewer1'");
  if (userRes.rows.length === 0) throw new Error('reviewer1 not found');
  const userId = userRes.rows[0].id;

  let outcomeRes = await dbQuery('SELECT id FROM outcomes LIMIT 1');
  if (outcomeRes.rows.length === 0) {
    outcomeRes = await dbQuery(
      `INSERT INTO outcomes (type, title, status, created_by)
       VALUES ('study', 'Evidence Test Outcome', 'draft', $1) RETURNING id`,
      [userId],
    );
  }
  return { userId, outcomeId: outcomeRes.rows[0].id };
}

afterAll(async () => {
  for (const id of createdEvidenceIds) {
    try { await dbQuery('DELETE FROM evidence WHERE id = $1', [id]); } catch {}
  }
  await closeDb();
});

describe('Evidence Integrity — production path', () => {
  test('uploadEvidence stores correct checksum', async () => {
    const { userId, outcomeId } = await getTestFixtures();
    const content = Buffer.from('evidence-upload-test-' + Date.now());
    const expected = computeFileChecksum(content);

    const result = await uploadEvidence(outcomeId, {
      buffer: content, filename: 'test-upload.txt', mimetype: 'text/plain',
    }, userId);

    createdEvidenceIds.push(result.id);
    expect(result.checksum_sha256).toBe(expected);
    expect(result.file_size).toBe(content.length);
  });

  test('downloadEvidence succeeds for untampered file', async () => {
    const { userId, outcomeId } = await getTestFixtures();
    const content = Buffer.from('untampered-' + Date.now());

    const uploaded = await uploadEvidence(outcomeId, {
      buffer: content, filename: 'ok.txt', mimetype: 'text/plain',
    }, userId);
    createdEvidenceIds.push(uploaded.id);

    const downloaded = await downloadEvidence(uploaded.id, userId);
    expect(downloaded.buffer.equals(content)).toBe(true);
  });

  test('downloadEvidence rejects tampered file', async () => {
    const { userId, outcomeId } = await getTestFixtures();
    const content = Buffer.from('tamper-test-' + Date.now());

    const uploaded = await uploadEvidence(outcomeId, {
      buffer: content, filename: 'tamper.txt', mimetype: 'text/plain',
    }, userId);
    createdEvidenceIds.push(uploaded.id);

    // Resolve real path and tamper
    const evRow = await dbQuery(
      'SELECT storage_path_encrypted FROM evidence WHERE id = $1', [uploaded.id],
    );
    const storagePath = decrypt(evRow.rows[0].storage_path_encrypted);
    await fs.writeFile(storagePath, 'TAMPERED CONTENT');

    await expect(downloadEvidence(uploaded.id, userId))
      .rejects.toThrow(/integrity/i);
  });
});
"}

