{"file_path": "/Users/aimanmengesha/Desktop/eagle point/Slopering/w2t11/repo/frontend/src/lib/offlineApi.js", "content": "import { api } from './api.js';
import { cacheGet, cacheSet } from './cache.js';
import { writable } from 'svelte/store';

export const isOnline = writable(true);

if (typeof window !== 'undefined') {
  window.addEventListener('online', () => isOnline.set(true));
  window.addEventListener('offline', () => isOnline.set(false));
}

export async function cachedGet(path, cacheKey, ttlMs = 5 * 60 * 1000) {
  // Try network first
  try {
    const result = await api.get(path);
    cacheSet(cacheKey || path, result, ttlMs);
    isOnline.set(true);
    return result;
  } catch (err) {
    // If network fails, try cache
    const cached = cacheGet(cacheKey || path);
    if (cached) {
      isOnline.set(false);
      return cached;
    }
    throw err;
  }
}

/**
 * Paths that must NEVER be queued for deferred replay because they depend
 * on immediate backend confirmation (locking, idempotency, optimistic
 * concurrency, time-sensitive validation, or server-state checks).
 *
 * Matched against `METHOD path` — e.g. "POST /holds".
 */
const NON_QUEUEABLE_PATTERNS = [
  // Constrained holds — require real-time slot locking
  /^POST \/holds$/,
  /^DELETE \/holds\//,
  /^POST \/holds\/.+\/checkout$/,

  // Cart checkout — requires drift/price recheck
  /^POST \/cart\/checkout$/,

  // Task accept & status — optimistic concurrency, version-locked
  /^POST \/tasks\/.+\/accept$/,
  /^PATCH \/tasks\/.+\/status$/,
  /^POST \/tasks\/.+\/assign$/,

  // Evidence upload — binary, not JSON-serializable for queue
  /^POST \/outcomes\/.+\/evidence$/,

  // Auth — session state, not replayable
  /^POST \/auth\//,
];

function isQueueable(method, path) {
  const key = `${method.toUpperCase()} ${path}`;
  return !NON_QUEUEABLE_PATTERNS.some((re) => re.test(key));
}

/**
 * Custom error for mutations rejected because the device is offline
 * and the operation is not safe to defer.
 */
export class OfflineError extends Error {
  constructor(message) {
    super(message || 'You are offline. This action requires an active connection.');
    this.name = 'OfflineError';
    this.code = 'OFFLINE';
    this.offline = true;
  }
}

/**
 * Attempt a mutation; on network failure:
 *  - if queueable → store for later replay and return `{ queued: true }`
 *  - if non-queueable → throw OfflineError so UI can show a clear message
 *
 * Callers may also pass `options.queueable = false` to force-reject queueing
 * even for paths not in the central blocklist.
 */
export async function mutationWithFallback(method, path, body, options = {}) {
  try {
    const result = await api[method](path, body);
    isOnline.set(true);
    return result;
  } catch (err) {
    const isNetworkError =
      err.message === 'Failed to fetch' || err.message?.includes('NetworkError');

    if (!isNetworkError) throw err;

    isOnline.set(false);

    // Determine if this mutation is safe to defer
    const explicitlyNonQueueable = options.queueable === false;
    const canQueue = !explicitlyNonQueueable && isQueueable(method, path);

    if (!canQueue) {
      throw new OfflineError();
    }

    // Safe to queue
    const { queueMutation } = await import('./mutationQueue.js');
    queueMutation(method.toUpperCase(), path, body);
    return { success: true, data: null, queued: true };
  }
}
"}

