// Inline the policy logic for isolated testing — keeps the test independent
// of Svelte stores and browser APIs while verifying the exact same patterns
// used in offlineApi.js.

const NON_QUEUEABLE_PATTERNS = [
  /^POST \/holds$/,
  /^DELETE \/holds\//,
  /^POST \/holds\/.+\/checkout$/,
  /^POST \/cart\/checkout$/,
  /^POST \/tasks\/.+\/accept$/,
  /^PATCH \/tasks\/.+\/status$/,
  /^POST \/tasks\/.+\/assign$/,
  /^POST \/outcomes\/.+\/evidence$/,
  /^POST \/auth\//,
];

function isQueueable(method, path) {
  const key = `${method.toUpperCase()} ${path}`;
  return !NON_QUEUEABLE_PATTERNS.some((re) => re.test(key));
}

describe('Offline Mutation Safety Policy', () => {
  // ── Non-queueable operations ──

  test('hold creation is non-queueable', () => {
    expect(isQueueable('POST', '/holds')).toBe(false);
  });

  test('hold cancel is non-queueable', () => {
    expect(isQueueable('DELETE', '/holds/some-uuid')).toBe(false);
  });

  test('hold checkout is non-queueable', () => {
    expect(isQueueable('POST', '/holds/some-uuid/checkout')).toBe(false);
  });

  test('cart checkout is non-queueable', () => {
    expect(isQueueable('POST', '/cart/checkout')).toBe(false);
  });

  test('task accept is non-queueable', () => {
    expect(isQueueable('POST', '/tasks/some-uuid/accept')).toBe(false);
  });

  test('task status transition is non-queueable', () => {
    expect(isQueueable('PATCH', '/tasks/some-uuid/status')).toBe(false);
  });

  test('task assign is non-queueable', () => {
    expect(isQueueable('POST', '/tasks/some-uuid/assign')).toBe(false);
  });

  test('evidence upload is non-queueable', () => {
    expect(isQueueable('POST', '/outcomes/some-uuid/evidence')).toBe(false);
  });

  test('auth login is non-queueable', () => {
    expect(isQueueable('POST', '/auth/login')).toBe(false);
  });

  // ── Queueable operations ──

  test('cart item add is queueable', () => {
    expect(isQueueable('POST', '/cart/items')).toBe(true);
  });

  test('cart item update is queueable', () => {
    expect(isQueueable('PUT', '/cart/items/some-id')).toBe(true);
  });

  test('cart item delete is queueable', () => {
    expect(isQueueable('DELETE', '/cart/items/some-id')).toBe(true);
  });

  test('SPU create is queueable', () => {
    expect(isQueueable('POST', '/spus')).toBe(true);
  });

  test('SPU update is queueable', () => {
    expect(isQueueable('PUT', '/spus/some-id')).toBe(true);
  });

  test('inventory write is queueable', () => {
    expect(isQueueable('POST', '/inventory')).toBe(true);
  });

  test('GET requests are always queueable (not blocked by policy)', () => {
    // GET requests wouldn't normally go through mutationWithFallback,
    // but the policy should not block them
    expect(isQueueable('GET', '/tasks')).toBe(true);
    expect(isQueueable('GET', '/holds/some-uuid')).toBe(true);
  });
});

describe('Mutation Queue Staleness', () => {
  test('entries older than 2 hours are considered stale', () => {
    const MAX_AGE_MS = 2 * 60 * 60 * 1000;
    const fresh = { timestamp: Date.now() - 30 * 60 * 1000 }; // 30 min
    const stale = { timestamp: Date.now() - 3 * 60 * 60 * 1000 }; // 3 hours

    expect(Date.now() - fresh.timestamp < MAX_AGE_MS).toBe(true);
    expect(Date.now() - stale.timestamp < MAX_AGE_MS).toBe(false);
  });
});

describe('Queue User Isolation', () => {
  test('queue keys are user-specific', () => {
    const QUEUE_PREFIX = 'petmed_mutation_queue_';
    const getQueueKey = (userId) => QUEUE_PREFIX + (userId || 'anonymous');

    expect(getQueueKey('user-1')).toBe('petmed_mutation_queue_user-1');
    expect(getQueueKey('user-2')).toBe('petmed_mutation_queue_user-2');
    expect(getQueueKey(null)).toBe('petmed_mutation_queue_anonymous');
    // Different users get different keys
    expect(getQueueKey('user-1')).not.toBe(getQueueKey('user-2'));
  });
});
"}

