  });

  test('SPU create is queueable', () => {
    expect(isQueueableMutation('POST', '/spus')).toBe(true);
  });

  test('SPU update is queueable', () => {
    expect(isQueueableMutation('PUT', '/spus/some-id')).toBe(true);
  });

  test('inventory write is queueable', () => {
    expect(isQueueableMutation('POST', '/inventory')).toBe(true);
  });

  test('GET requests are not blocked by policy', () => {
    expect(isQueueableMutation('GET', '/tasks')).toBe(true);
    expect(isQueueableMutation('GET', '/holds/some-uuid')).toBe(true);
  });
});

describe('Mutation Queue Staleness', () => {
  test('entries older than 2 hours are considered stale', () => {
    const MAX_AGE_MS = 2 * 60 * 60 * 1000;
    const fresh = { timestamp: Date.now() - 30 * 60 * 1000 };
    const stale = { timestamp: Date.now() - 3 * 60 * 60 * 1000 };

    expect(Date.now() - fresh.timestamp < MAX_AGE_MS).toBe(true);
    expect(Date.now() - stale.timestamp < MAX_AGE_MS).toBe(false);
  });
});

describe('Queue User Isolation', () => {
  test('queue keys are user-specific', () => {
    const QUEUE_PREFIX = 'petmed_mutation_queue_';
    const getQueueKey = (userId) => QUEUE_PREFIX + (userId || 'anonymous');

    expect(getQueueKey('user-1')).toBe('petmed_mutation_queue_user-1');
    expect(getQueueKey('user-2')).toBe('petmed_mutation_queue_user-2');
    expect(getQueueKey(null)).toBe('petmed_mutation_queue_anonymous');
    expect(getQueueKey('user-1')).not.toBe(getQueueKey('user-2'));
  });
});
"}
